import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"敌楼与城墙","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/badaling/dilou.md","filePath":"landmarks/badaling/dilou.md","lastUpdated":1784720050000}'),l={name:"landmarks/badaling/dilou.md"};function n(s,t,i,g,d,h){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="敌楼与城墙" tabindex="-1">敌楼与城墙 <a class="header-anchor" href="#敌楼与城墙" aria-label="Permalink to &quot;敌楼与城墙&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1716929955955-f6ef9c1ca084?w=1200&amp;q=80" alt="敌楼与城墙"></p><blockquote><p>垛口如齿，马道如带。每一块城砖的缝隙里，都浇着六百年前的糯米灰浆。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>从<a href="/beijing-travel-guide/landmarks/badaling/guancheng.html">关城</a>北门拾级而上，脚下便是八达岭长城的主体——<strong>城墙与敌楼</strong>。八达岭段是明长城砖石工程的典范：墙身以条石为基、城砖包砌，内填夯土碎石，砖缝间浇灌石灰与糯米汁拌合的<strong>糯米灰浆</strong>，黏合之牢，历经六百年风雨兵燹而墙体不散。</p><p>八达岭城墙平均高七八米，基部宽约6.5米，<strong>顶宽逾4.5米，可容五马并骑、十人并行</strong>。墙顶铺墁方砖的马道平整宽阔，既是兵力调动的通道，也是当年守军纵马巡边的&quot;高速公路&quot;。</p><p>敌楼则随山势起伏、依间隔布设，从关城一路向<a href="/beijing-travel-guide/landmarks/badaling/beibalou.html">北八楼</a>攀登，便是在一座座敌楼之间穿行。北线前半程敌楼最密集，是边走边看、读懂长城建筑的最佳路段。</p><p>城墙并非&quot;一堵直墙&quot;，而是&quot;因地形，用险制塞&quot;：陡处砌成阶梯，缓处铺为马道，高低宽窄皆随山形而变。读懂了脚下的墙，才算真正开始读懂长城。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>城墙高度</strong></td><td style="text-align:left;">平均7-8米（依地势6-9米不等）</td></tr><tr><td style="text-align:left;"><strong>基部宽度</strong></td><td style="text-align:left;">约6.5米</td></tr><tr><td style="text-align:left;"><strong>墙顶宽度</strong></td><td style="text-align:left;">逾4.5米，&quot;五马并骑、十人并行&quot;</td></tr><tr><td style="text-align:left;"><strong>敌楼类型</strong></td><td style="text-align:left;">空心敌楼（驻兵储粮）、实心敌楼（瞭望传烽）</td></tr><tr><td style="text-align:left;"><strong>墙顶设施</strong></td><td style="text-align:left;">外侧垛口（带射孔）、内侧女墙</td></tr><tr><td style="text-align:left;"><strong>排水系统</strong></td><td style="text-align:left;">墙顶石槽汇集雨水，经吐水嘴排出墙基外</td></tr><tr><td style="text-align:left;"><strong>砌筑工艺</strong></td><td style="text-align:left;">条石为基、城砖包砌、糯米灰浆灌缝</td></tr></tbody></table><h3 id="空心敌楼与实心敌楼" tabindex="-1">空心敌楼与实心敌楼 <a class="header-anchor" href="#空心敌楼与实心敌楼" aria-label="Permalink to &quot;空心敌楼与实心敌楼&quot;">​</a></h3><p>敌楼分两种。<strong>空心敌楼</strong>内部为拱券结构，可驻兵数十人、储存粮草兵器，战时是独立的作战堡垒——这种楼制由戚继光在明隆庆年间创制并推广于长城沿线，八达岭北线即以空心敌楼为主，越往高处楼体越大，直至雄踞山顶的北八楼。</p><p><strong>实心敌楼</strong>则以砖石实心填砌，顶部设铺房或垛台，专司瞭望与举放烽燧。两种敌楼一实一空、一守一望，在城墙上交替布设，构成攻防一体的防御链条。</p><h3 id="垛口、射孔与排水" tabindex="-1">垛口、射孔与排水 <a class="header-anchor" href="#垛口、射孔与排水" aria-label="Permalink to &quot;垛口、射孔与排水&quot;">​</a></h3><p>墙顶外侧的<strong>垛口</strong>高约两米，口下开<strong>射孔</strong>与<strong>瞭望孔</strong>，守军可凭垛隐蔽射击、探身瞭望；内侧设<strong>女墙</strong>防止人马坠落。一外一内之间，便是当年守军战斗与生活的一线空间。</p><p>最容易被忽略的是城墙的<strong>排水系统</strong>：墙顶微微向内倾斜，雨水汇入沿墙设置的石槽，再经伸出墙外的<strong>吐水嘴</strong>排出墙基之外，避免雨水冲刷墙根。正是这些不起眼的细节，让砖石长城得以在数百年的冻融雨雪中屹立不倒。</p><h3 id="城砖上的-责任制" tabindex="-1">城砖上的&quot;责任制&quot; <a class="header-anchor" href="#城砖上的-责任制" aria-label="Permalink to &quot;城砖上的&quot;责任制&quot;&quot;">​</a></h3><p>仔细观察墙体，部分城砖上仍可辨认出<strong>烧制年代与窑户姓名</strong>的戳印——这是明代城砖质量责任制的物证：哪段墙、哪块砖出了问题，可以一路追查到窑厂。正是这种近乎苛刻的制度，铸就了明长城的坚固。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="糯米灰浆-古代-水泥-的秘密" tabindex="-1">糯米灰浆：古代&quot;水泥&quot;的秘密 <a class="header-anchor" href="#糯米灰浆-古代-水泥-的秘密" aria-label="Permalink to &quot;糯米灰浆：古代&quot;水泥&quot;的秘密&quot;">​</a></h3><p>现代检测发现，明代长城砖缝中的灰浆含有支链淀粉成分，正是糯米汁与石灰拌合的产物。糯米灰浆黏性极强、耐水抗震，是中国古代建筑工艺的独门秘方。</p><p>八达岭城墙能在数百年的冻融、地震与战火中保持整体不散，这层看不见的&quot;糯米夹心&quot;功不可没。在博物馆的修筑工具展区（见<a href="/beijing-travel-guide/landmarks/badaling/changcheng-museum.html">中国长城博物馆</a>），可以了解这套工艺从配料到灌浆的完整流程。</p><h3 id="五马并骑的马道" tabindex="-1">五马并骑的马道 <a class="header-anchor" href="#五马并骑的马道" aria-label="Permalink to &quot;五马并骑的马道&quot;">​</a></h3><p>&quot;墙顶宽可五马并骑&quot;并非文学夸张，而是明代长城的营造标准：八达岭段墙顶实测宽4.5-5.8米，足以让五匹战马并辔驰过。守军凭马道快速机动，哪段告急便驰援哪段，使绵延数里的城墙成为一个联动的防御整体。</p><p>马道边缘内侧的女墙、每隔一段设置的登城台阶（马道出入口），也都是为机动服务的细节——长城不是&quot;一堵墙&quot;，而是一套会呼吸、能调度的防御系统。</p><h3 id="烽火传信-一日夜驰报京师" tabindex="-1">烽火传信：一日夜驰报京师 <a class="header-anchor" href="#烽火传信-一日夜驰报京师" aria-label="Permalink to &quot;烽火传信：一日夜驰报京师&quot;">​</a></h3><p>敌楼与城外墩台构成烽燧网络，明代对举烽有严格&quot;军规&quot;：敌约百人，举一烟放一炮；约五百人，两烟两炮；约千人，三烟三炮；约五千人，四烟四炮；万人以上，五烟五炮。昼烟夜火、烟炮相续，军情沿长城一线接力传递，很快便可从边墩驰报至京师。</p><p>你在城墙上看到的一座座敌楼，既是堡垒，也是这座&quot;光与烟的电报网&quot;上的节点。</p><p>如今烽烟散尽，但从敌楼上向城外山脊望去，仍能寻到孤立墩台的残影——它们当年与城上敌楼昼夜对答，把万里边疆连成一张会呼吸的预警网。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>空心敌楼券洞</strong>：钻入敌楼内部，看拱券结构与瞭望射孔如何构成一座微型堡垒。</li><li><strong>垛口与射孔</strong>：在垛口后站一站，体会守军凭垛御敌的射击视角。</li><li><strong>吐水嘴</strong>：寻找墙外伸出的石雕吐水嘴，那是城墙数百年不倒的排水功臣。</li><li><strong>字砖寻踪</strong>：留意砖面模糊的戳印，那是明代窑户留下的六百年&quot;签名&quot;。</li><li><strong>马道远眺</strong>：立于宽阔马道之上，看敌楼沿山脊串珠成链、直奔北八楼。</li><li><strong>女墙对比</strong>：对照外侧高垛口与内侧低女墙，理解&quot;御敌&quot;与&quot;护己&quot;的一墙两用。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>边走边看</strong>：从关城登北线的前半程（北一楼至北四楼一带）敌楼最密集，是观察建筑细节的最佳路段。</li><li><strong>勿刻勿摸</strong>：城砖字印为珍贵文物，严禁刻画拓印，轻触观赏即可。</li><li><strong>垛口勿攀爬</strong>：外侧垛口之外即是深谷，拍照时勿坐卧垛墙、勿探身过猛。</li><li><strong>雨天防滑</strong>：雨后马道砖面湿滑，吐水嘴附近尤甚，注意脚下。</li><li><strong>带着问题登城</strong>：登城前在<a href="/beijing-travel-guide/landmarks/badaling/changcheng-museum.html">中国长城博物馆</a>看一眼敌楼模型，再对照实物，收获翻倍。</li><li><strong>顺势上行</strong>：观察完敌楼细节后，继续沿马道向<a href="/beijing-travel-guide/landmarks/badaling/beibalou.html">北八楼</a>攀登，完成北线登顶。</li></ul><hr><p><strong>📍 位置</strong>：八达岭长城南北两线主体（自关城登城即入） <strong>⏱️ 建议游览</strong>：40-60分钟（含登城步行） <strong>🔗 上一站</strong>：<a href="/beijing-travel-guide/landmarks/badaling/guancheng.html">关城与城门</a>（出北门即上城墙） <strong>🔗 下一站</strong>：<a href="/beijing-travel-guide/landmarks/badaling/beibalou.html">北八楼与好汉坡</a>（沿马道继续上行） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/badaling/">八达岭长城概览</a></p>',35)])])}const b=a(l,[["render",n]]);export{q as __pageData,b as default};
